import React, { useEffect, useState, useCallback } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

const TimbangMuat = () => {
  const navigate = useNavigate();

  const [rfid, setRfid] = useState(null);
  const [truck, setTruck] = useState(null);
  const [loading, setLoading] = useState(false);

  const [form, setForm] = useState({
    itemType: '',
    quantity: '',
    tara: ''
  });

  const [timbangMuatList, setTimbangMuatList] = useState([]);

  // ================= RFID FETCH =================
  const fetchRFID = useCallback(async () => {
    try {
      setLoading(true);
      const res = await axios.get('http://localhost:5000/api/rfid/latest');

      if (res.data.truck) {
        setRfid(res.data.truck.truckId);
        setTruck(res.data.truck);
        fetchTimbangMuat(res.data.truck.truckId);
      }

    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    const interval = setInterval(() => {
      if (!rfid) fetchRFID();
    }, 2000);

    return () => clearInterval(interval);
  }, [rfid, fetchRFID]);

  // ================= FORM HANDLER =================
  const handleChange = (e) => {
    setForm({
      ...form,
      [e.target.name]: e.target.value
    });
  };

  // ================= SUBMIT =================
  const handleSubmit = async (e) => {
    e.preventDefault();

    const payload = {
      truckId: rfid,
      itemType: form.itemType,
      quantity: Number(form.quantity),
      tara: Number(form.tara),
      unit: 'Kg'
    };

    try {
      await axios.post('http://localhost:5000/api/loadings', payload);

      alert("Data berhasil disimpan!");

      setForm({
        itemType: '',
        quantity: '',
        tara: ''
      });

      fetchTimbangMuat(rfid);

    } catch (err) {
      console.error(err);
      alert("Gagal menyimpan data timbang muat");
    }
  };

  // ================= FETCH LIST =================
  const fetchTimbangMuat = async (truckId) => {
    try {
      const res = await axios.get(
        `http://localhost:5000/api/loadings/${truckId}`
      );

      setTimbangMuatList(res.data);

    } catch (err) {
      console.error(err);
    }
  };

  // ================= UI =================
  return (
    <div className="p-8 min-h-screen bg-gradient-to-br from-blue-100 to-white">
      <h1 className="text-3xl font-bold text-center mb-8">
        📦 Timbang Muat
      </h1>

      {loading && (
        <div className="flex justify-center items-center my-10">
          <div className="animate-spin rounded-full h-16 w-16 border-t-4 border-blue-500"></div>
        </div>
      )}

      {!truck && !loading && (
        <div className="text-center text-gray-600 mb-8">
          🔄 Menunggu scan RFID...
        </div>
      )}

      {truck && (
        <div className="max-w-5xl mx-auto bg-white rounded-lg shadow-lg p-6">

          {/* ================= TRUCK INFO ================= */}
          <div className="mb-6">
            <h2 className="text-xl font-semibold text-blue-600 text-center mb-4">
              Data Truk
            </h2>

            <div className="grid grid-cols-2 gap-4">
              <div><b>Truck ID:</b> {truck.truckId}</div>
              <div><b>Driver:</b> {truck.driver}</div>
              <div><b>Tipe Truck:</b> {truck.truckType}</div>
              <div><b>Tanggal:</b> {truck.date?.split('T')[0]}</div>
            </div>
          </div>

          {/* ================= FORM ================= */}
          <form onSubmit={handleSubmit} className="grid grid-cols-2 gap-4">

            <div>
              <label>Jenis Barang</label>
              <input
                name="itemType"
                value={form.itemType}
                onChange={handleChange}
                className="border p-2 w-full rounded"
                required
              />
            </div>

            <div>
              <label>Jumlah</label>
              <input
                type="number"
                name="quantity"
                value={form.quantity}
                onChange={handleChange}
                className="border p-2 w-full rounded"
                required
              />
            </div>

            <div>
              <label>Tara (kg)</label>
              <input
                type="number"
                name="tara"
                value={form.tara}
                onChange={handleChange}
                className="border p-2 w-full rounded"
                required
              />
            </div>

            <div className="col-span-2 flex justify-end gap-4 mt-4">
              <button
                type="button"
                onClick={() => navigate(-1)}
                className="bg-gray-400 text-white px-4 py-2 rounded"
              >
                Kembali
              </button>

              <button
                type="submit"
                className="bg-blue-600 text-white px-4 py-2 rounded"
              >
                Simpan
              </button>
            </div>
          </form>

          {/* ================= TABLE ================= */}
          <div className="mt-10">
            <h3 className="font-bold mb-3">Riwayat Timbang Muat</h3>

            <div className="overflow-x-auto">
              <table className="w-full text-sm border">

                <thead className="bg-blue-200">
                  <tr>
                    <th className="border p-2">Truck</th>
                    <th className="border p-2">Driver</th>
                    <th className="border p-2">Item</th>
                    <th className="border p-2">Qty</th>
                    <th className="border p-2">Tara</th>
                    <th className="border p-2">Bruto</th>
                    <th className="border p-2">Netto</th>
                    <th className="border p-2">Unit</th>
                  </tr>
                </thead>

                <tbody>
                  {timbangMuatList.map((item, i) => (
                    <tr key={i} className="hover:bg-gray-100">

                      <td className="border p-2">{truck.truckId}</td>
                      <td className="border p-2">{truck.driver}</td>
                      <td className="border p-2">{item.itemType}</td>
                      <td className="border p-2">{item.quantity}</td>

                      <td className="border p-2">
                        {item.tara ?? '-'} kg
                      </td>

                      <td className="border p-2">
                        {item.bruto ?? '-'} kg
                      </td>

                      <td className="border p-2 font-semibold">
                        {item.netto ?? '-'} kg
                      </td>

                      <td className="border p-2">
                        {item.unit}
                      </td>

                    </tr>
                  ))}

                  {timbangMuatList.length === 0 && (
                    <tr>
                      <td colSpan="8" className="text-center p-4 text-gray-500">
                        Belum ada data
                      </td>
                    </tr>
                  )}
                </tbody>

              </table>
            </div>

          </div>

        </div>
      )}
    </div>
  );
};

export default TimbangMuat;
